package org.example;

import io.javalin.Javalin;

public class App {
    public String getGreeting() {
        return "Hello World!";
    }

    public static void main(String[] args) {
        System.out.println(new App().getGreeting());
        var app = Javalin.create(config ->  {
            config.routes.get(
                    "/test" ,
                    ctx -> ctx.result("Hello World!")
            );
        }).start(8080);
    }
}
